import{_ as d,o as t,c as o,a4 as a}from"./chunks/framework.4M7SpZrd.js";const m=JSON.parse('{"title":"Usuarios & Acesso","description":"","frontmatter":{},"headers":[],"relativePath":"admin/users-access.md","filePath":"admin/users-access.md"}'),i={name:"admin/users-access.md"};function c(s,e,r,n,l,u){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="usuarios-acesso" tabindex="-1">Usuarios &amp; Acesso <a class="header-anchor" href="#usuarios-acesso" aria-label="Permalink to &quot;Usuarios &amp; Acesso&quot;">​</a></h1><p>Gerenciamento de usuarios, convites, leads e verificacao de identidade.</p><hr><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><blockquote><p><strong>Admin pages:</strong> <code>/users</code>, <code>/users/[id]</code><strong>Backend:</strong> <code>app/api/v1/admin/users.py</code> — 4 endpoints</p></blockquote><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/users</code></td><td>Lista paginada com filtros (<code>search</code>, <code>plan</code>, <code>is_admin</code>, <code>date_from</code>, <code>date_to</code>). Usa window function para count total.</td></tr><tr><td><code>GET</code></td><td><code>/admin/users/{id}</code></td><td>Detalhe completo: perfil, plano, assinatura, buscas, alertas, identidade, embeddings.</td></tr><tr><td><code>PATCH</code></td><td><code>/admin/users/{id}</code></td><td>Editar campos (<code>is_admin</code>, <code>is_active</code>, <code>plan_id</code>). Gera audit log.</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/users/{id}</code></td><td>Desativar usuario (soft delete). Gera audit log.</td></tr></tbody></table><p>A pagina de detalhe <code>/users/[id]</code> exibe a timeline completa do usuario, incluindo historico de buscas, alertas recebidos e status de verificacao de identidade.</p><hr><h2 id="convites" tabindex="-1">Convites <a class="header-anchor" href="#convites" aria-label="Permalink to &quot;Convites&quot;">​</a></h2><blockquote><p><strong>Admin page:</strong> <code>/convites</code><strong>Backend:</strong> <code>app/api/v1/admin/invites.py</code> — 3 endpoints</p></blockquote><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/invites</code></td><td>Lista codigos de convite com filtros de status (<code>active</code>, <code>used</code>, <code>revoked</code>).</td></tr><tr><td><code>POST</code></td><td><code>/admin/invites</code></td><td>Gerar novo(s) codigo(s) de convite. Campos: quantidade, plano associado, expiracao.</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/invites/{id}</code></td><td>Revogar codigo de convite.</td></tr></tbody></table><hr><h2 id="leads" tabindex="-1">Leads <a class="header-anchor" href="#leads" aria-label="Permalink to &quot;Leads&quot;">​</a></h2><blockquote><p><strong>Admin page:</strong> <code>/leads</code><strong>Backend:</strong> <code>app/api/v1/admin/leads.py</code> — 3 endpoints</p></blockquote><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/leads</code></td><td>Lista leads capturados pela landing page (<code>email</code>, <code>nome</code>, <code>data</code>, <code>opted_in</code>).</td></tr><tr><td><code>GET</code></td><td><code>/admin/leads/{id}</code></td><td>Detalhe do lead.</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/leads/{id}</code></td><td>Remover lead.</td></tr></tbody></table><hr><h2 id="identidades" tabindex="-1">Identidades <a class="header-anchor" href="#identidades" aria-label="Permalink to &quot;Identidades&quot;">​</a></h2><blockquote><p><strong>Admin page:</strong> <code>/identidades</code><strong>Backend:</strong> <code>app/api/v1/admin/identities.py</code> — 5 endpoints</p></blockquote><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/identities/stats</code></td><td>Totais: verificados, pendentes, rejeitados, total de embeddings.</td></tr><tr><td><code>GET</code></td><td><code>/admin/identities</code></td><td>Lista paginada com filtros de status (<code>none</code>, <code>pending</code>, <code>verified</code>, <code>rejected</code>) e data.</td></tr><tr><td><code>GET</code></td><td><code>/admin/identities/{user_id}</code></td><td>Detalhe da verificacao. <strong>Nunca expoe embedding raw.</strong></td></tr><tr><td><code>PATCH</code></td><td><code>/admin/identities/{user_id}</code></td><td>Aprovar ou rejeitar verificacao. Gera audit log.</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/identities/{user_id}/embedding</code></td><td>Revogar embedding (conformidade LGPD). Gera audit log.</td></tr></tbody></table><p>Cada aprovacao ou rejeicao de identidade gera um registro de audit log e pode disparar notificacao por email ao usuario.</p><hr><h2 id="notas-de-seguranca" tabindex="-1">Notas de Seguranca <a class="header-anchor" href="#notas-de-seguranca" aria-label="Permalink to &quot;Notas de Seguranca&quot;">​</a></h2><ul><li>Todos os endpoints exigem autenticacao de admin (<code>is_admin=true</code>).</li><li>Operacoes sensiveis (editar, desativar, aprovar/rejeitar, revogar embedding) geram audit logs automaticamente.</li><li>Embeddings faciais nunca sao expostos em respostas de API — apenas metadados e status.</li><li>Remocao de embeddings segue conformidade LGPD (direito ao esquecimento).</li></ul>',23)])])}const h=d(i,[["render",c]]);export{m as __pageData,h as default};
